def _wagers_text(wagers: list[Wager]) -> str:
    if not wagers:
        return "❌ <i>Not Submitted</i>"
    parts = [f"✅ {esc(w.player_name)} ({w.wager_type})" for w in wagers]
    text = ", ".join(parts)
    left = MAX_WAGERS_PER_MATCH - len(wagers)
